import {
  charsFontWidth12pixelsSize400Map,
  charsFontWidth12pixelsSize500Map,
} from '../../text-ellipsis/chars-font-width-map.js';
import { calculateWidth } from '../../text-ellipsis/truncate-string.js';

/**
 * Helper function to calculate total width for multiple strings using font weight 400 map.
 * Includes validation for finite values and fallback to 0 for invalid calculations.
 */
export const calculateTotalWidth400 = (
  ...texts: (string | undefined | null)[]
): number => {
  let totalWidth = 0;

  for (const text of texts) {
    if (text) {
      const width = calculateWidth(text, charsFontWidth12pixelsSize400Map);
      totalWidth += isFinite(width) ? width : 0;
    }
  }

  return totalWidth;
};

